tokenMapTemplate.css:
. -{name} {
  /* Color */
  --f-{name}-bg:           var(--f-brand-color-background-{semantic});
  --f-{name}-bg-hover:     var(--f-brand-color-background-{semantic}-hover);
  --f-{name}-text:         var(--f-brand-color-text-{semantic});
  --f-{name}-border:       var(--f-brand-color-border-{semantic});
  --f-{name}-icon:         var(--f-brand-color-icon-{semantic});
  /* Sizing */
  --f-{name}-radius:       var(--f-brand-radius-{size});
  --f-{name}-padding-v:    var(--f-brand-space-{size});
  --f-{name}-padding-h:    var(--f-brand-space-{size});
  --f-{name}-gap:          var(--f-brand-space-{size});
  /* Typography */
  --f-{name}-font:         var(--f-brand-type-{style});
  /* Motion */
  --f-{name}-duration:     var(--f-brand-motion-duration-{speed});
  --f-{name}-easing:       var(--f-brand-motion-easing-{curve});
  /* Shadow */
  --f-{name}-shadow:       var(--f-brand-shadow-{level});
  /* States */
  --f-{name}-bg-disabled:  var(--f-brand-color-background-disabled);
  --f-{name}-text-disabled:var(--f-brand-color-text-disabled);
}
